import{_ as a,c as i,o as t,aj as o}from"./chunks/framework.guNMSiFm.js";const u=JSON.parse('{"title":"SDK Tutorials","description":"","frontmatter":{},"headers":[],"relativePath":"guide/tutorials/index.md","filePath":"guide/tutorials/index.md","lastUpdated":1777621302000}'),r={name:"guide/tutorials/index.md"};function l(s,e,d,n,h,c){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="sdk-tutorials" tabindex="-1">SDK Tutorials <a class="header-anchor" href="#sdk-tutorials" aria-label="Permalink to &quot;SDK Tutorials&quot;">​</a></h1><p>These pages summarize the current Iroha 3 client entry points shipped from the main workspace. The SDK surface is evolving quickly, so this section focuses on the canonical package names, installation paths, and minimal starting points from the upstream repository.</p><h2 id="recommended-order" tabindex="-1">Recommended Order <a class="header-anchor" href="#recommended-order" aria-label="Permalink to &quot;Recommended Order&quot;">​</a></h2><ol><li><a href="/iroha-2-docs/get-started/install-iroha-2.html">Install Iroha 3</a></li><li><a href="/iroha-2-docs/get-started/launch-iroha-2.html">Launch Iroha 3</a></li><li>Pick an SDK: <ul><li><a href="/iroha-2-docs/guide/tutorials/rust.html">Rust</a></li><li><a href="/iroha-2-docs/guide/tutorials/python.html">Python</a></li><li><a href="/iroha-2-docs/guide/tutorials/javascript.html">JavaScript / TypeScript</a></li><li><a href="/iroha-2-docs/guide/tutorials/kotlin-java.html">Android, Kotlin, and Java</a></li><li><a href="/iroha-2-docs/guide/tutorials/swift.html">Swift and iOS</a></li></ul></li><li>Review the <a href="/iroha-2-docs/guide/tutorials/sample-apps.html">sample apps</a> when you want a complete client application reference.</li><li>Use <a href="/iroha-2-docs/guide/tutorials/kaigi.html">Embed Kaigi</a> when you want to add wallet-backed audio/video meetings to your own app.</li><li>Use <a href="/iroha-2-docs/guide/tutorials/musubi.html">Musubi packages</a> when you need reusable Kotodama source libraries with pinned on-chain registry dependencies.</li></ol><h2 id="sample-apps" tabindex="-1">Sample Apps <a class="header-anchor" href="#sample-apps" aria-label="Permalink to &quot;Sample Apps&quot;">​</a></h2><p>We maintain sample applications for JavaScript desktop, Android, and iOS client flows. The JavaScript demo is the most complete external reference. Swift/iOS examples exist in the upstream workspace under <code>examples/ios/</code>, but their checked-in project manifests are currently out of sync with the package API and dependency layout. The external mobile point demos are useful mostly for layout and historical context.</p><ul><li><a href="/iroha-2-docs/guide/tutorials/sample-apps.html">Sample apps overview</a></li><li><a href="/iroha-2-docs/guide/tutorials/kaigi.html">Embed Kaigi in a JavaScript app</a></li></ul><h2 id="source-of-truth" tabindex="-1">Source of Truth <a class="header-anchor" href="#source-of-truth" aria-label="Permalink to &quot;Source of Truth&quot;">​</a></h2><p>All SDK pages here are derived from the current upstream workspace:</p><ul><li><code>crates/iroha</code></li><li><code>python/iroha_python</code></li><li><code>javascript/iroha_js</code></li><li><code>java/iroha_android</code></li><li><code>IrohaSwift</code></li><li><code>crates/musubi</code></li></ul><p>When in doubt, prefer the README and package metadata in those directories over older Iroha 2-era examples.</p>',11)])])}const m=a(r,[["render",l]]);export{u as __pageData,m as default};
